const app = document.querySelector('#app').__vue_app__;
const pinia = app.config.globalProperties.$pinia;

// Try to find keycloak instance - it's likely in a module scope
// Let's check what's available in the window or via the auth store
const keycloakKeys = Object.keys(window).filter(k => k.toLowerCase().includes('keycloak'));

// Also try to access Keycloak via the auth store's closure
// We can check the token directly
const authState = pinia.state.value.auth;
const token = authState.accessToken;

// Decode access token
const accessPayload = JSON.parse(atob(token.split('.')[1]));

JSON.stringify({
  windowKeycloakKeys: keycloakKeys,
  accessTokenClaims: Object.keys(accessPayload),
  accessTokenScope: accessPayload.scope,
  accessTokenAzp: accessPayload.azp,
}, null, 2);

// Try to access the Keycloak instance through various means
// keycloak-js sometimes attaches to window, or we can check module scope

// Method 1: Check if Keycloak is on window
const kc = window.Keycloak || window.keycloak;

// Method 2: Check localStorage/sessionStorage for keycloak data
const kcStorage = {};
for (let i = 0; i < sessionStorage.length; i++) {
  const key = sessionStorage.key(i);
  if (key && key.includes('kc')) {
    kcStorage[key] = sessionStorage.getItem(key);
  }
}
for (let i = 0; i < localStorage.length; i++) {
  const key = localStorage.key(i);
  if (key && (key.includes('kc') || key.includes('keycloak'))) {
    kcStorage['ls_' + key] = localStorage.getItem(key);
  }
}

// Method 3: Try to get the ID token from cookies
const cookies = document.cookie.split(';').map(c => c.trim()).filter(c => c.includes('kc'));

JSON.stringify({ kcOnWindow: !!kc, kcStorage, kcCookies: cookies }, null, 2);

